export const ALL_REPORTS = REPORT_CATALOG.flatMap(c =>
  c.reports.map(r => ({ ...r, category: c.label, categoryKey: c.key }))
)

export function findReport(id) {
  return ALL_REPORTS.find(r => r.id === id) || null
}
